1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	export function processScenario(input: any): unknown {
13	  const items = input.steps[0].items;
14	  if (items.length === 0) {
15	    return { results: [{ premium: PROCESSING_FEE }] };
16	  }
17	  let basePremium: number;
18	  if (items.length === 3 && items.every((item: any) => item.type === "rune")) {
19	    basePremium = 60;
20	  } else {
21	    basePremium = items.reduce(
22	      (sum: number, item: any) => sum + BASE_PREMIUM_BY_TYPE[item.type],
23	      0,
24	    );
25	  }
26	  const premium = basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
27	  return { results: [{ premium }] };
28	}
